import StatusBadge from '../complaints/StatusBadge';

/**
 * AdminDashboard Component
 * For admins/staff to manage all complaints
 */
const AdminDashboard = () => {
  const { complaints, isLoading, error, updateStatus, assignComplaint } = useComplaint();
  const { user } = useAuth();

  // Local state for filters and actions
  const [filterStatus, setFilterStatus] = useState('');
  const [filterCategory, setFilterCategory] = useState('');
  const [filterPriority, setFilterPriority] = useState('');
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedComplaint, setSelectedComplaint] = useState(null);
  const [actionLoading, setActionLoading] = useState(false);
  const [actionMessage, setActionMessage] = useState('');

  // Filter and search complaints
  const filteredComplaints = useMemo(() => {
    return complaints.filter((complaint) => {
      const matchStatus = !filterStatus || complaint.status === filterStatus;
      const matchCategory = !filterCategory || complaint.category === filterCategory;
      const matchPriority = !filterPriority || complaint.priority === filterPriority;
      const matchSearch =
        !searchTerm ||
        complaint.complaint_number.toLowerCase().includes(searchTerm.toLowerCase()) ||
        complaint.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
        (complaint.student?.name || '').toLowerCase().includes(searchTerm.toLowerCase());

      return matchStatus && matchCategory && matchPriority && matchSearch;
    });
  }, [complaints, filterStatus, filterCategory, filterPriority, searchTerm]);

  // Calculate statistics
  const stats = useMemo(() => {
    return {
      total: complaints.length,
      open: complaints.filter((c) => c.status === 'open').length,
      assigned: complaints.filter((c) => c.status === 'assigned').length,
      in_progress: complaints.filter((c) => c.status === 'in_progress').length,
      resolved: complaints.filter((c) => c.status === 'resolved').length,
      closed: complaints.filter((c) => c.status === 'closed').length,
    };
  }, [complaints]);

  // Handle status update
  const handleStatusChange = async (complaintId, newStatus) => {
    setActionLoading(true);
    setActionMessage('');

    try {
      const result = await updateStatus(complaintId, newStatus, 'Status updated by admin');

      if (result.success) {
        setActionMessage('✅ Status updated successfully');
        setSelectedComplaint(null);
        setTimeout(() => setActionMessage(''), 3000);
      } else {
        setActionMessage(`❌ Error: ${result.error}`);
      }
    } catch (err) {
      setActionMessage(`❌ Error: ${err.message}`);
    } finally {
      setActionLoading(false);
    }
  };

  // Handle assign complaint
  const handleAssign = async (complaintId, staffId) => {
    if (!staffId) {
      setActionMessage('❌ Please select a staff member');
      return;
    }

    setActionLoading(true);
    setActionMessage('');

    try {
      const result = await assignComplaint(complaintId, staffId);

      if (result.success) {
        setActionMessage('✅ Complaint assigned successfully');
        setSelectedComplaint(null);
        setTimeout(() => setActionMessage(''), 3000);
      } else {
        setActionMessage(`❌ Error: ${result.error}`);
      }
    } catch (err) {
      setActionMessage(`❌ Error: ${err.message}`);
    } finally {
      setActionLoading(false);
    }
  };

  const categories = [
    'Hostel & Accommodation',
    'Academic',
    'Canteen / Food',
    'Transport',
    'Infrastructure',
    'IT / Wi-Fi',
    'Medical',
    'Safety & Security',
    'Other',
  ];

  const priorities = ['low', 'medium', 'high', 'critical'];
  const statuses = ['open', 'assigned', 'in_progress', 'resolved', 'closed', 'reopened'];

  return (
    <div className="space-y-8">
      {/* Header */}
      <div className="glass-card p-8 space-y-2">
        <h1 className="text-3xl font-bold text-slate-900">📊 Admin Dashboard</h1>
        <p className="text-slate-600">Manage all complaints and track resolution</p>
      </div>

      {/* Statistics Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-6 gap-4">
        {[
          { label: 'Total', value: stats.total, icon: '📋', color: 'from-blue-400 to-blue-600' },
          { label: 'Open', value: stats.open, icon: '🔵', color: 'from-blue-400 to-blue-600' },
          { label: 'Assigned', value: stats.assigned, icon: '👤', color: 'from-yellow-400 to-yellow-600' },
          { label: 'Progress', value: stats.in_progress, icon: '⚙️', color: 'from-purple-400 to-purple-600' },
          { label: 'Resolved', value: stats.resolved, icon: '✅', color: 'from-emerald-400 to-emerald-600' },
          { label: 'Closed', value: stats.closed, icon: '🔒', color: 'from-slate-400 to-slate-600' },
        ].map((stat, idx) => (
          <div key={idx} className="glass-card p-4 text-center space-y-2">
            <div className="text-2xl">{stat.icon}</div>
            <p className="text-2xl font-bold text-slate-900">{stat.value}</p>
            <p className="text-xs text-slate-600">{stat.label}</p>
          </div>
        ))}
      </div>

      {/* Filters */}
      <div className="glass-card p-6 space-y-4">
        <h2 className="font-bold text-slate-900">🔍 Filters & Search</h2>

        {/* Search Bar */}
        <input
          type="text"
          placeholder="Search by complaint #, title, or student name..."
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          className="w-full px-4 py-3 rounded-lg border border-slate-300 bg-white/70 focus:outline-none focus:ring-2 focus:ring-blue-200 transition-all"
        />

        {/* Filter Grid */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          {/* Status Filter */}
          <div className="space-y-2">
            <label className="text-sm font-semibold text-slate-700">Status</label>
            <select
              value={filterStatus}
              onChange={(e) => setFilterStatus(e.target.value)}
              className="w-full px-4 py-2 rounded-lg border border-slate-300 bg-white/70 focus:outline-none focus:ring-2 focus:ring-blue-200"
            >
              <option value="">All Statuses</option>
              {statuses.map((s) => (
                <option key={s} value={s}>
                  {s.replace('_', ' ').toUpperCase()}
                </option>
              ))}
            </select>
          </div>

          {/* Category Filter */}
          <div className="space-y-2">
            <label className="text-sm font-semibold text-slate-700">Category</label>
            <select
              value={filterCategory}
              onChange={(e) => setFilterCategory(e.target.value)}
              className="w-full px-4 py-2 rounded-lg border border-slate-300 bg-white/70 focus:outline-none focus:ring-2 focus:ring-blue-200"
            >
              <option value="">All Categories</option>
              {categories.map((c) => (
                <option key={c} value={c}>
                  {c}
                </option>
              ))}
            </select>
          </div>

          {/* Priority Filter */}
          <div className="space-y-2">
            <label className="text-sm font-semibold text-slate-700">Priority</label>
            <select
              value={filterPriority}
              onChange={(e) => setFilterPriority(e.target.value)}
              className="w-full px-4 py-2 rounded-lg border border-slate-300 bg-white/70 focus:outline-none focus:ring-2 focus:ring-blue-200"
            >
              <option value="">All Priorities</option>
              {priorities.map((p) => (
                <option key={p} value={p}>
                  {p.toUpperCase()}
                </option>
              ))}
            </select>
          </div>
        </div>

        {/* Clear Filters */}
        <button
          onClick={() => {
            setFilterStatus('');
            setFilterCategory('');
            setFilterPriority('');
            setSearchTerm('');
          }}
          className="text-sm text-blue-600 hover:text-blue-700 font-semibold"
        >
          ✕ Clear All Filters
        </button>
      </div>

      {/* Action Message */}
      {actionMessage && (
        <div className={`p-4 rounded-lg text-sm font-semibold ${
          actionMessage.includes('✅')
            ? 'bg-emerald-50 text-emerald-700 border border-emerald-200'
            : 'bg-red-50 text-red-700 border border-red-200'
        }`}>
          {actionMessage}
        </div>
      )}

      {/* Error Message */}
      {error && (
        <div className="bg-red-50 border border-red-200 rounded-lg p-4 text-red-700 text-sm">
          Error: {error}
        </div>
      )}

      {/* Complaints List */}
      <div className="space-y-4">
        <h2 className="font-bold text-slate-900">
          📋 Complaints ({filteredComplaints.length} of {complaints.length})
        </h2>

        {isLoading && <div className="glass-card p-8 text-center text-slate-600">Loading...</div>}

        {!isLoading && filteredComplaints.length === 0 && (
          <div className="glass-card p-8 text-center space-y-3">
            <p className="text-2xl">📪</p>
            <p className="text-slate-600">No complaints match your filters</p>
          </div>
        )}

        {filteredComplaints.map((complaint) => (
          <div
            key={complaint.id}
            className="glass-card p-6 space-y-3 hover:shadow-lg transition-all cursor-pointer"
            onClick={() => setSelectedComplaint(selectedComplaint?.id === complaint.id ? null : complaint)}
          >
            {/* Main Info */}
            <div className="flex items-start justify-between">
              <div className="flex-1">
                <p className="font-mono text-sm text-blue-600">{complaint.complaint_number}</p>
                <p className="text-lg font-bold text-slate-900">{complaint.title}</p>
                <p className="text-sm text-slate-600 mt-1">{complaint.category}</p>
              </div>
              <div className="flex gap-3">
                <StatusBadge status={complaint.status} />
                <span className={`px-3 py-1.5 rounded-full font-semibold text-sm ${
                  complaint.priority === 'critical' ? 'bg-red-100 text-red-700' :
                  complaint.priority === 'high' ? 'bg-orange-100 text-orange-700' :
                  complaint.priority === 'medium' ? 'bg-yellow-100 text-yellow-700' :
                  'bg-blue-100 text-blue-700'
                }`}>
                  {complaint.priority.toUpperCase()}
                </span>
              </div>
            </div>

            {/* Student & Date Info */}
            <div className="flex items-center justify-between pt-2 border-t border-slate-200 text-sm text-slate-600">
              <span>
                👤 {complaint.student?.name || 'Unknown'} ({complaint.student?.email || 'N/A'})
              </span>
              <span>
                📅 {new Date(complaint.created_at).toLocaleDateString('en-US', {
                  year: 'numeric',
                  month: 'short',
                  day: 'numeric',
                })}
              </span>
            </div>

            {/* Assigned Staff if exists */}
            {complaint.assigned_user && (
              <div className="text-sm text-slate-600">
                ✓ Assigned to: <span className="font-semibold">{complaint.assigned_user.name}</span>
              </div>
            )}

            {/* Expandable Details */}
            {selectedComplaint?.id === complaint.id && (
              <div className="pt-4 space-y-4 border-t border-slate-200 bg-slate-50/50 p-4 rounded-lg">
                <div className="space-y-2">
                  <p className="text-sm font-semibold text-slate-700">Description:</p>
                  <p className="text-sm text-slate-600">{complaint.description}</p>
                </div>

                {/* Status Update */}
                <div className="space-y-2">
                  <label className="text-sm font-semibold text-slate-700">Change Status:</label>
                  <select
                    onClick={(e) => e.stopPropagation()}
                    onChange={(e) => handleStatusChange(complaint.id, e.target.value)}
                    disabled={actionLoading}
                    className="w-full px-3 py-2 rounded-lg border border-slate-300 bg-white text-sm focus:outline-none focus:ring-2 focus:ring-blue-200 disabled:opacity-50"
                  >
                    <option value="">Select new status...</option>
                    {statuses.map((s) => (
                      <option key={s} value={s}>
                        {s.replace('_', ' ').toUpperCase()}
                      </option>
                    ))}
                  </select>
                </div>

                {/* Assign to Staff */}
                {complaint.status !== 'closed' && (
                  <div className="space-y-2">
                    <label className="text-sm font-semibold text-slate-700">Assign to Staff:</label>
                    <select
                      onClick={(e) => e.stopPropagation()}
                      onChange={(e) => handleAssign(complaint.id, e.target.value)}
                      disabled={actionLoading}
                      className="w-full px-3 py-2 rounded-lg border border-slate-300 bg-white text-sm focus:outline-none focus:ring-2 focus:ring-blue-200 disabled:opacity-50"
                    >
                      <option value="">Select staff member...</option>
                      <option value="staff-001">Staff Member 1</option>
                      <option value="staff-002">Staff Member 2</option>
                      <option value="staff-003">Staff Member 3</option>
                    </select>
                  </div>
                )}
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

export default AdminDashboard;
